// HasChildrenFile applies the HasEdge predicate on the "children_file" edge.
func HasChildrenFile() predicate.DriveFile {
	return predicate.DriveFile(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ChildrenFileTable, ChildrenFileColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasChildrenFileWith applies the HasEdge predicate on the "children_file" edge with a given conditions (other predicates).
func HasChildrenFileWith(preds ...predicate.DriveFile) predicate.DriveFile {
	return predicate.DriveFile(func(s *sql.Selector) {
		step := newChildrenFileStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

